#include <stdio.h>

int main() {
    int n, sum = 0;
    scanf("%d", &n);

    for (int i = 1; i <= n; i++) {
        if (n % i == 0) {
            sum += i;
        }
    }

    printf("%d\n", sum);
    return 0;
}

#include <stdio.h>

int main() {
    int n, digit_sum = 0, digit_count = 0;
    scanf("%d", &n);

    int temp = n;
    while (temp > 0) {
        digit_sum += temp % 10;
        digit_count++;
        temp /= 10;
    }

    printf("%d\n", digit_sum);
    printf("%d\n", digit_count);
    return 0;
}

#include <stdio.h>

int main() {
    int k;
    scanf("%d", &k);

    int a = 0, b = 1;

    for (int i = 1; i <= k; i++) {
        if (i == 1) {
            printf("%d\n", a);
        } else if (i == 2) {
            printf("%d\n", b);
        } else {
            int c = a + b;
            printf("%d\n", c);
            a = b;
            b = c;
        }
    }

    return 0;
}

#include <stdio.h>

int main() {
    int n;
    scanf("%d", &n);

    long long factorial = 1;
    for (int i = 1; i <= n; i++) {
        factorial *= i;
    }

    printf("%lld\n", factorial);

    if (factorial % 2 == 0) {
        printf("EVEN\n");
    } else {
        printf("ODD\n");
    }

    return 0;
}

#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main() {
    char password[101];
    scanf("%s", password);

    int criteria = 0;
    int length = strlen(password);
    int has_digit = 0, has_lower = 0, has_upper = 0;

    if (length >= 8) {
        criteria++;
    }

    for (int i = 0; password[i] != '\0'; i++) {
        if (isdigit(password[i])) {
            has_digit = 1;
        }
        if (islower(password[i])) {
            has_lower = 1;
        }
        if (isupper(password[i])) {
            has_upper = 1;
        }
    }

    if (has_digit) criteria++;
    if (has_lower) criteria++;
    if (has_upper) criteria++;

    printf("%d\n", criteria);

    if (criteria >= 3) {
        printf("STRONG\n");
    } else {
        printf("WEAK\n");
    }

    return 0;
}

#include <stdio.h>

int main() {
    int n;
    scanf("%d", &n);

    int is_prime = 1;

    for (int i = 2; i * i <= n; i++) {
        if (n % i == 0) {
            is_prime = 0;
            break;
        }
    }

    if (is_prime) {
        printf("PRIME\n");
    } else {
        printf("NOT PRIME\n");
    }

    return 0;
}

#include <stdio.h>

int main() {
    int a, b;
    scanf("%d %d", &a, &b);

    int original_a = a, original_b = b;

    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }

    int gcd = a;
    long long lcm = ((long long)original_a * original_b) / gcd;

    printf("%d\n", gcd);
    printf("%lld\n", lcm);

    return 0;
}

#include <stdio.h>

int main() {
    int n;
    scanf("%d", &n);

    int original = n;
    int reversed = 0;

    while (n > 0) {
        reversed = reversed * 10 + (n % 10);
        n /= 10;
    }

    printf("%d\n", reversed);

    if (original == reversed) {
        printf("PALINDROME\n");
    } else {
        printf("NOT PALINDROME\n");
    }

    return 0;
}

#include <stdio.h>

int main() {
    int m, n;
    scanf("%d %d", &m, &n);

    int count = 0;

    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            if (j % i == 0) {
                count++;
            }
        }
    }

    printf("%d\n", count);

    return 0;
}

#include <stdio.h>

int main() {
    int k;
    scanf("%d", &k);

    double sum = 0.0;

    for (int i = 0; i < k; i++) {
        double score;
        scanf("%lf", &score);
        sum += score;
    }

    double average = sum / k;

    printf("%.1f\n", average);

    if (average >= 90) {
        printf("A\n");
    } else if (average >= 80) {
        printf("B\n");
    } else if (average >= 70) {
        printf("C\n");
    } else if (average >= 60) {
        printf("D\n");
    } else {
        printf("F\n");
    }

    return 0;
}
